func FileMd5sum(filePath string) (string, error) {
	file, errop := os.Open(filePath)
	if errop != nil {
		return "", fmt.Errorf("unable to copy file content to md5: %v", errop)
	}
	defer file.Close()

	reader := bufio.NewReader(file)
	hash := md5.New()
	if _, err := io.Copy(hash, reader); err != nil {
		return "", fmt.Errorf("error computing md5: %v", err)
	}

	hashInBytes := hash.Sum(nil)[:16]
	sum := hex.EncodeToString(hashInBytes)

	return sum, nil
}

func GenerateRepositoryWebHookSecret(hookSecretKey, vcsName, repoName string) string {
	pass := fmt.Sprintf("%s-%s", vcsName, repoName)
	keyBytes := pbkdf2.Key([]byte(pass), []byte(hookSecretKey), 4096, 128, sha512.New)
	key64 := base64.StdEncoding.EncodeToString(keyBytes)
	return key64
}

func (c *client) CDNItemDownload(ctx context.Context, cdnAddr string, hash string, itemType sdk.CDNItemType, md5Sum string, writer io.WriteSeeker) error {
	currentRetry := 0
	var lastError error
	for i := 0; i <= c.config.Retry; i++ {
		currentRetry++
		if _, err := writer.Seek(0, io.SeekStart); err != nil {
			return sdk.NewErrorFrom(sdk.ErrUnknownError, "unable to reset writer: %v", err)
		}

		reader, _, code, err := c.StreamNoRetry(ctx, c.HTTPNoTimeoutClient(), http.MethodGet, fmt.Sprintf("%s/item/%s/%s/download", cdnAddr, itemType, hash), nil, func(req *http.Request) {
			auth := "Bearer " + c.config.SessionToken
			req.Header.Add("Authorization", auth)
		})
		if code >= 500 {
			lastError = err
			continue
		}

		if err != nil {
			return err
		}

		md5Hash := md5.New()
		multiWriter := io.MultiWriter(md5Hash, writer)

		if _, err := io.Copy(multiWriter, reader); err != nil {
			lastError = fmt.Errorf("unable to read cdn response: %v", err)
			log.Error(ctx, "%v", lastError)
			continue
		}

		md5S := hex.EncodeToString(md5Hash.Sum(nil))
		if md5S != md5Sum {
			lastError = fmt.Errorf("ms5 doesn't match: Want %s Got %s", md5Sum, md5S)
			log.Error(ctx, "%v", lastError)
			continue
		}
		return nil
	}
	return fmt.Errorf("unable to get data after %d retries: %v", currentRetry, lastError)
}

func (m *Mapper) NewTableMapping(target interface{}, name string, autoIncrement bool, keys ...string) TableMapping {
	v := sdk.ValueFromInterface(target)

	if v.Kind() != reflect.Struct {
		err := fmt.Errorf("TableMapping error: target (%T) must be a struct", target)
		panic(err)
	}

	var (
		encryptedEntity bool
		encryptedFields []EncryptedField
		signedEntity    bool
	)

	fields := deepFields(target)
	for i := 0; i < len(fields); i++ {
		dbTag, okDBTag := fields[i].Tag.Lookup("db")
		if !okDBTag {
			continue
		}

		tagValues := strings.Split(dbTag, ",")
		if len(tagValues) == 0 {
			continue
		}

		gmTag, okGMTag := fields[i].Tag.Lookup("gorpmapping")
		if okGMTag {
			tagValues := strings.Split(gmTag, ",")
			if len(tagValues) == 0 {
				continue
			}
			column := strings.SplitN(dbTag, ",", 2)[0]

			if tagValues[0] == "encrypted" {
				encryptedEntity = true
				encryptedFields = append(encryptedFields, EncryptedField{
					Name:   fields[i].Name,
					Extras: tagValues[1:],
					Column: column,
				})
			}
		}
	}

	for i := 0; i < v.NumField(); i++ {
		if v.Type().Field(i).Name == reflect.TypeOf(SignedEntity{}).Name() {
			signedEntity = true
		}
	}

	if signedEntity {
		x, ok := target.(Canonicaller)
		if !ok {
			err := fmt.Errorf("TableMapping error: target (%T) must implement Canonicaller interface because it's a signed entity", target)
			panic(err)
		}

		if _, ok := target.(Signed); !ok {
			err := fmt.Errorf("TableMapping error: target (%T) must implement Signed interface because it's a signed entity", target)
			panic(err)
		}

		tmplStrFuncs := x.Canonical()
		for _, f := range tmplStrFuncs {
			h := sha1.New()
			_, _ = h.Write(f.Bytes())
			bs := h.Sum(nil)
			sha := fmt.Sprintf("%x", bs)

			t := template.New(sha)
			var err error

			t = t.Funcs(template.FuncMap{
				"print": func(i interface{}) string {
					return fmt.Sprintf("%v", err)
				},
				"printDate": func(i time.Time) string {
					return i.In(time.UTC).Format(time.RFC3339)
				},
				"hash": func(i interface{}) string {
					var dataBts []byte
					dataString, is := i.(string)
					if !is {
						dataBts, _ := yaml.Marshal(i)
						dataString = string(dataBts)
					} else {
						dataBts = []byte(dataString)
					}
					return fmt.Sprintf("%x", md5.Sum(dataBts))
				},
			})

			t, err = t.Parse(f.String())
			if err != nil {
				err := fmt.Errorf("TableMapping error: target (%T) canonical function \"%s\" is invalid: %v", target, f.String(), err)
				panic(err)
			}
			m.CanonicalFormTemplates.L.Lock()
			m.CanonicalFormTemplates.M[sha] = t
			m.CanonicalFormTemplates.L.Unlock()
		}
	}

	return TableMapping{
		Target:          target,
		Name:            name,
		AutoIncrement:   autoIncrement,
		Keys:            keys,
		SignedEntity:    signedEntity,
		EncryptedEntity: encryptedEntity,
		EncryptedFields: encryptedFields,
	}
}

