func (l *ldapDriver) openLDAP(ctx context.Context, conf Config) error {
	if l.conn != nil {
		l.conn.Close()
	}
	var err error
	l.conf = conf

	address := fmt.Sprintf("%s:%d", l.conf.Host, l.conf.Port)

	log.Info(ctx, "Auth> Preparing connection to LDAP server: %s", address)
	if !l.conf.SSL {
		l.conn, err = ldap.Dial("tcp", address)
		if err != nil {
			log.Error(ctx, "Auth> Cannot dial %s : %s", address, err)
			return sdk.WithStack(sdk.ErrLDAPConn)
		}

		//Reconnect with TLS
		err = l.conn.StartTLS(&tls.Config{InsecureSkipVerify: true})
		if err != nil {
			log.Error(ctx, "Auth> Cannot start TLS %s : %s", address, err)
			return sdk.WithStack(sdk.ErrLDAPConn)
		}
	} else {
		log.Info(ctx, "Auth> Connecting to LDAP server")
		l.conn, err = ldap.DialTLS("tcp", address, &tls.Config{
			ServerName:         l.conf.Host,
			InsecureSkipVerify: false,
		})
		if err != nil {
			log.Error(ctx, "Auth> Cannot dial TLS (InsecureSkipVerify=false) %s : %s", address, err)
			return sdk.WithStack(sdk.ErrLDAPConn)
		}
	}

	if l.conf.ManagerDN != "" {
		log.Info(ctx, "LDAP> bind manager %s", l.conf.ManagerDN)
		if err := l.conn.Bind(l.conf.ManagerDN, l.conf.ManagerPassword); err != nil {
			if shoudRetry(ctx, err) {
				if err := l.openLDAP(ctx, l.conf); err != nil {
					return err
				}
				if err := l.conn.Bind(l.conf.ManagerDN, l.conf.ManagerPassword); err != nil {
					return sdk.WithStack(err)
				}
			} else {
				return err
			}
		}
	}

	return nil
}

func HashPassword(password string) ([]byte, error) {
	hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
	if err != nil {
		return nil, sdk.WrapError(err, "cannot generate hash for given password")
	}
	return hash, nil
}

func (x RunningStorageUnits) HashLocator(loc string) string {
	salt := []byte(x.config.HashLocatorSalt)
	hashLocator := hex.EncodeToString(pbkdf2.Key([]byte(loc), salt, 4096, 32, sha1.New))
	return hashLocator
}

func (s *Service) completeItem(ctx context.Context, tx gorpmapper.SqlExecutorWithTx, itemUnit sdk.CDNItemUnit) error {
	// We need to lock the item and set its status to complete and also generate data hash
	it, err := item.LoadAndLockByID(ctx, s.Mapper, tx, itemUnit.ItemID)
	if err != nil {
		if sdk.ErrorIs(err, sdk.ErrNotFound) {
			return sdk.WrapError(sdk.ErrLocked, "item already locked")
		}
		return err
	}

	ctx = context.WithValue(ctx, storage.FieldAPIRef, it.APIRefHash)

	// Update item with final data
	it.Status = sdk.CDNStatusItemCompleted

	var reader io.ReadCloser
	for _, unit := range s.Units.Buffers {
		if unit.ID() == itemUnit.UnitID {
			reader, err = unit.NewReader(ctx, itemUnit)
			if err != nil {
				return err
			}
			break
		}
	}
	if reader == nil {
		for _, unit := range s.Units.Storages {
			if unit.ID() == itemUnit.UnitID {
				reader, err = unit.NewReader(ctx, itemUnit)
				if err != nil {
					return err
				}
				break
			}
		}
		if reader == nil {
			return sdk.WithStack(fmt.Errorf("unable to find unit storage %s", itemUnit.ID))
		}
	}

	// Compte md5 and sha512
	md5Hash := md5.New()
	sha512Hash := sha512.New()
	// For optimum speed, Getpagesize returns the underlying system's memory page size.
	pagesize := os.Getpagesize()
	// wraps the Reader object into a new buffered reader to read the files in chunks
	// and buffering them for performance.
	mreader := bufio.NewReaderSize(reader, pagesize)
	multiWriter := io.MultiWriter(md5Hash, sha512Hash)
	size, err := io.Copy(multiWriter, mreader)
	if err != nil {
		_ = reader.Close()
		return sdk.WithStack(err)
	}
	if err := reader.Close(); err != nil {
		return sdk.WithStack(err)
	}

	sha512S := hex.EncodeToString(sha512Hash.Sum(nil))
	md5S := hex.EncodeToString(md5Hash.Sum(nil))

	it.Hash = sha512S
	it.MD5 = md5S
	it.Size = size

	if err := item.Update(ctx, s.Mapper, tx, it); err != nil {
		return err
	}

	log.Info(ctx, "completeItem> item %s has been completed", it.ID)

	return nil
}

func (s *Service) storeFile(ctx context.Context, sig cdn.Signature, reader io.ReadCloser, storeFileOptions StoreFileOptions) (*sdk.CDNItem, error) {
	var itemType sdk.CDNItemType
	switch {
	case sig.Worker.RunResultName != "":
		itemType = sdk.CDNTypeItemRunResultV2
	case sig.Worker.FileName != "":
		itemType = sdk.CDNTypeItemRunResult
	case sig.Worker.CacheTag != "":
		itemType = sdk.CDNTypeItemWorkerCache
	default:
		return nil, sdk.WrapError(sdk.ErrWrongRequest, "invalid item type")
	}
	bufferUnit := s.Units.FileBuffer()

	// Item and ItemUnit creation
	apiRef, err := sdk.NewCDNApiRef(itemType, sig)
	if err != nil {
		return nil, err
	}
	hashRef, err := apiRef.ToHash()
	if err != nil {
		return nil, err
	}

	// Check Item unicity
	_, err = item.LoadByAPIRefHashAndType(ctx, s.Mapper, s.mustDBWithCtx(ctx), hashRef, itemType)
	if err == nil {
		return nil, sdk.NewErrorFrom(sdk.ErrInvalidData, "cannot upload the same file twice: %s", apiRef.ToFilename())
	}
	if !sdk.ErrorIs(err, sdk.ErrNotFound) {
		return nil, err
	}

	it := &sdk.CDNItem{
		APIRef:     apiRef,
		Type:       itemType,
		APIRefHash: hashRef,
		Status:     sdk.CDNStatusItemIncoming,
	}

	if !storeFileOptions.DisableApiRunResult {
		switch itemType {
		case sdk.CDNTypeItemRunResultV2:
			runResultV2ApiRef, _ := it.GetCDNRunResultApiRefV2()

			// Call CDS API to check if we can upload the run result
			runResult, err := s.Client.V2QueueJobRunResultGet(ctx, runResultV2ApiRef.RunJobRegion, runResultV2ApiRef.RunJobID, runResultV2ApiRef.RunResultID)
			if err != nil {
				return nil, sdk.WrapError(err, "unable to get run result from API")
			}

			if runResult.Status != sdk.V2WorkflowRunResultStatusPending {
				return nil, sdk.NewError(sdk.ErrWrongRequest, fmt.Errorf("run result %q must be PENDING and was %q", runResult.ID, runResult.Status))
			}

		case sdk.CDNTypeItemRunResult:
			// Call CDS API to check if we can upload the run result
			runResultApiRef, _ := it.GetCDNRunResultApiRef()

			runResultCheck := sdk.WorkflowRunResultCheck{
				Name:       runResultApiRef.ArtifactName,
				ResultType: runResultApiRef.RunResultType,
				RunID:      runResultApiRef.RunID,
				RunNodeID:  runResultApiRef.RunNodeID,
				RunJobID:   runResultApiRef.RunJobID,
			}
			code, err := s.Client.QueueWorkflowRunResultCheck(ctx, sig.JobID, runResultCheck)
			if err != nil {
				if code == http.StatusConflict {
					return nil, sdk.NewErrorFrom(sdk.ErrInvalidData, "unable to upload the same file twice: %s", runResultApiRef.ToFilename())
				}
				if code == http.StatusForbidden {
					return nil, sdk.NewErrorFrom(sdk.ErrForbidden, err.Error())
				}
				return nil, err
			}
		}
	}

	iu, err := s.Units.NewItemUnit(ctx, bufferUnit, it)
	if err != nil {
		return nil, err
	}

	// Create Destination Writer
	writer, err := bufferUnit.NewWriter(ctx, *iu)
	if err != nil {
		return nil, err
	}

	// Compute md5 and sha512
	md5Hash := md5.New()
	sha512Hash := sha512.New()

	sizeWriter := &SizeWriter{}

	// For optimum speed, Getpagesize returns the underlying system's memory page size.
	pagesize := os.Getpagesize()
	// wraps the Reader object into a new buffered reader to read the files in chunks
	// and buffering them for performance.
	mreader := bufio.NewReaderSize(reader, pagesize)
	multiWriter := io.MultiWriter(md5Hash, sha512Hash, sizeWriter)

	teeReader := io.TeeReader(mreader, multiWriter)

	if err := bufferUnit.Write(*iu, teeReader, writer); err != nil {
		_ = reader.Close()
		_ = writer.Close()
		return nil, sdk.WithStack(err)
	}
	if err := reader.Close(); err != nil {
		return nil, sdk.WithStack(err)
	}
	sha512S := hex.EncodeToString(sha512Hash.Sum(nil))
	md5S := hex.EncodeToString(md5Hash.Sum(nil))

	it.Hash = sha512S
	it.MD5 = md5S
	it.Size = sizeWriter.Size
	it.Status = sdk.CDNStatusItemCompleted

	// Insert Item and ItemUnit in database
	tx, err := s.mustDBWithCtx(ctx).Begin()
	if err != nil {
		return nil, sdk.WithStack(err)
	}
	defer tx.Rollback() //nolint

	// Insert Item
	if err := item.Insert(ctx, s.Mapper, tx, it); err != nil {
		return nil, err
	}

	// Insert Item Unit
	iu.ItemID = iu.Item.ID
	if err := storage.InsertItemUnit(ctx, s.Mapper, tx, iu); err != nil {
		return nil, err
	}

	if !storeFileOptions.DisableApiRunResult {
		runResultApiRef, _ := it.GetCDNRunResultApiRef()
		switch itemType {
		case sdk.CDNTypeItemRunResult:
			var result interface{}
			switch runResultApiRef.RunResultType {
			case sdk.WorkflowRunResultTypeArtifact:
				result = sdk.WorkflowRunResultArtifact{
					WorkflowRunResultArtifactCommon: sdk.WorkflowRunResultArtifactCommon{
						Name: apiRef.ToFilename(),
					},
					Size:       it.Size,
					MD5:        it.MD5,
					CDNRefHash: it.APIRefHash,
					Perm:       runResultApiRef.Perm,
				}
			case sdk.WorkflowRunResultTypeCoverage:
				result = sdk.WorkflowRunResultCoverage{
					WorkflowRunResultArtifactCommon: sdk.WorkflowRunResultArtifactCommon{
						Name: apiRef.ToFilename(),
					},
					Size:       it.Size,
					MD5:        it.MD5,
					CDNRefHash: it.APIRefHash,
					Perm:       runResultApiRef.Perm,
				}
			}

			bts, err := json.Marshal(result)
			if err != nil {
				return nil, sdk.WithStack(err)
			}
			wrResult := sdk.WorkflowRunResult{
				WorkflowRunID:     sig.RunID,
				WorkflowNodeRunID: sig.NodeRunID,
				WorkflowRunJobID:  sig.JobID,
				Type:              runResultApiRef.RunResultType,
				DataRaw:           json.RawMessage(bts),
			}
			if err := s.Client.QueueWorkflowRunResultsAdd(ctx, sig.JobID, wrResult); err != nil {
				return nil, err
			}
		}
	}

	if err := tx.Commit(); err != nil {
		return nil, sdk.WithStack(err)
	}

	s.Units.PushInSyncQueue(ctx, it.ID, it.Created)

	// For worker cache item clean others with same ref to purge old cached data
	if itemType == sdk.CDNTypeItemWorkerCache {
		tx, err := s.mustDBWithCtx(ctx).Begin()
		if err != nil {
			return nil, sdk.WithStack(err)
		}
		defer tx.Rollback() //nolint

		if err := s.cleanPreviousCachedData(ctx, tx, sig, apiRef.ToFilename()); err != nil {
			return nil, err
		}

		if err := tx.Commit(); err != nil {
			return nil, sdk.WithStack(err)
		}
	}

	return it, nil
}

func ListenGerritStreamEvent(ctx context.Context, store cache.Store, goRoutines *sdk.GoRoutines, vcsGerritConfig sdk.VCSGerritConfiguration, gerritEventChan chan<- GerritEvent) error {
	ctx, cancel := context.WithCancel(ctx)
	defer cancel()
	signer, err := ssh.ParsePrivateKey([]byte(vcsGerritConfig.SSHPrivateKey))
	if err != nil {
		return sdk.WithStack(err)
	}

	// Create config
	config := &ssh.ClientConfig{
		User: vcsGerritConfig.SSHUsername,
		Auth: []ssh.AuthMethod{
			ssh.PublicKeys(signer),
		},
		HostKeyCallback: ssh.InsecureIgnoreHostKey(),
	}

	URL, _ := url.Parse(vcsGerritConfig.URL)

	// Dial TCP
	conn, err := ssh.Dial("tcp", fmt.Sprintf("%s:%d", URL.Hostname(), vcsGerritConfig.SSHPort), config)
	if err != nil {
		return sdk.WithStack(err)
	}
	defer conn.Close()

	session, err := conn.NewSession()
	if err != nil {
		return sdk.WithStack(err)
	}
	defer session.Close()

	r, w := io.Pipe()
	defer r.Close()
	defer w.Close()
	session.Stdout = w

	stdoutreader := bufio.NewReader(r)

	goRoutines.Exec(ctx, "gerrit-ssh-run", func(ctx context.Context) {
		// Run command
		log.Debug(ctx, "Listening to gerrit event stream %s", vcsGerritConfig.URL)
		if err := session.Run("gerrit stream-events"); err != nil {
			log.Error(ctx, "ListenGerritStreamEvent> unable to run gerrit stream-events command: %v", err)
		}
		cancel()
		r.Close()
		return
	})

	lockKey := cache.Key("gerrit", "event", "lock")
	tick := time.NewTicker(50 * time.Millisecond)
	for {
		select {
		case <-ctx.Done():
			return ctx.Err()
		case <-tick.C:
			line, errs := stdoutreader.ReadString('\n')
			if errs == io.EOF {
				continue
			}
			if errs != nil {
				log.Warn(ctx, "ListenGerritStreamEvent> unable to read string")
				continue
			}
			if line == "" {
				continue
			}
			var event GerritEvent
			lineBytes := []byte(line)
			if err := sdk.JSONUnmarshal(lineBytes, &event); err != nil {
				log.Error(ctx, "gerrit: unable to read event %v: %s", err, line)
				continue
			}

			log.Debug(ctx, "gerrit: event received %s", line)

			// Avoid that 2 hook uservice dispatch the same event
			// Take the lock to dispatch an event
			locked, err := store.Lock(lockKey, time.Minute, 100, 15)
			if err != nil {
				log.Error(ctx, "gerrit: unable to lock %s: %v", lockKey, err)
			}

			// compute md5
			hasher := md5.New()
			hasher.Write(lineBytes) // nolint
			md5 := hex.EncodeToString(hasher.Sum(nil))

			// check if this event has already been dispatched
			k := cache.Key("gerrit", "event", "id", md5)
			var existString string
			b, _ := store.Get(k, &existString)
			if !b {
				if err := store.SetWithTTL(k, md5, 300); err != nil {
					log.Warn(ctx, "gerrit: unable to set %s", k)
				}
			}

			// release lock
			if locked {
				if err := store.Unlock(lockKey); err != nil {
					log.Error(ctx, "gerrit: unable to unlock %s: %v", lockKey, err)
				}
			}

			if !b {
				gerritEventChan <- event
			} else {
				log.Info(ctx, "gerrit: skipping event")
			}
		}
	}

}

